import type { Column } from "elements";
import { Button } from "elements";
import { h } from "vue";
import type { Order, OrderColumnHandlers, OrderStatus } from "./types";

// Status label map for display
const STATUS_LABELS: Record<OrderStatus, string> = {
  pending: "Pending",
  processing: "Processing",
  shipped: "Shipped",
  delivered: "Delivered",
  cancelled: "Cancelled",
};

// Status CSS class map for badge styling
const STATUS_CLASSES: Record<OrderStatus, string> = {
  pending: "status-pending",
  processing: "status-processing",
  shipped: "status-shipped",
  delivered: "status-delivered",
  cancelled: "status-cancelled",
};

// Currency formatter for USD
const CURRENCY_FORMATTER = new Intl.NumberFormat("en-US", {
  style: "currency",
  currency: "USD",
});

// Date formatter for medium style
const DATE_FORMATTER = new Intl.DateTimeFormat("en-US", {
  dateStyle: "medium",
});

export const createColumns = (
  handlers: OrderColumnHandlers,
): Column<Order>[] => [
  {
    id: "id",
    label: "Order",
    cell: ({ row }) =>
      h("span", { class: "font-mono"}, `#${row.original.id}`),
  },
  {
    id: "customer",
    label: "Customer",
    isSortable: true,
  },
  {
    id: "status",
    label: "Status",
    isSortable: true,
    cell: ({ row }) => {
      const status = row.original.status;
      return h("span", { class: STATUS_CLASSES[status] }, STATUS_LABELS[status]);
    },
  },
  {
    id: "items",
    label: "Items",
    isSortable: true,
  },
  {
    id: "total",
    label: "Total",
    isSortable: true,
    cell: ({ row }) => CURRENCY_FORMATTER.format(row.original.total),
  },
  {
    id: "date",
    label: "Date",
    isSortable: true,
    cell: ({ row }) => DATE_FORMATTER.format(new Date(row.original.date)),
  },
  {
    id: "actions",
    cell: ({ row }) => [
      h(
        Button,
        {
          variant: "ghost",
          size: "sm",
          onClick: () => handlers.onView(row.original),
        },
        () => "View",
      ),
      h(
        Button,
        {
          variant: "destructive",
          size: "sm",
          onClick: () => handlers.onCancel(row.original),
        },
        () => "Cancel",
      ),
    ],
  },
];

