import type { Column } from "elements";
import type { Order, OrderStatus } from "./types";

const statusLabels: Record<OrderStatus, string> = {
  pending: "Pending",
  processing: "Processing",
  shipped: "Shipped",
  delivered: "Delivered",
  cancelled: "Cancelled",
};

const statusClasses: Record<OrderStatus, string> = {
  pending: "status-pending",
  processing: "status-processing",
  shipped: "status-shipped",
  delivered: "status-delivered",
  cancelled: "status-cancelled",
};

const currencyFormatter = new Intl.NumberFormat("en-US", {
  style: "currency",
  currency: "USD",
});

const dateFormatter = new Intl.DateTimeFormat("en-US", {
  dateStyle: "medium",
});

export const createColumns = (handlers: {
  onView: (order: Order) => void;
  onCancel: (order: Order) => void;
}): Column<Order>[] => [
  {
    id: "id",
    label: "Order",
    isSortable: false,
    cellRenderer: (order: Order) => {
      return `<span class="font-mono">#ORD-${order.id}</span>`;
    },
  },
  {
    id: "customer",
    label: "Customer",
    isSortable: true,
  },
  {
    id: "status",
    label: "Status",
    isSortable: false,
    cellRenderer: (order: Order) => {
      const label = statusLabels[order.status];
      const className = statusClasses[order.status];
      return `<span class="badge ${className}">${label}</span>`;
    },
  },
  {
    id: "items",
    label: "Items",
    isSortable: true,
  },
  {
    id: "total",
    label: "Total",
    isSortable: true,
    cellRenderer: (order: Order) => {
      return currencyFormatter.format(order.total);
    },
  },
  {
    id: "date",
    label: "Date",
    isSortable: true,
    cellRenderer: (order: Order) => {
      return dateFormatter.format(new Date(order.date));
    },
  },
  {
    id: "actions",
    label: "Actions",
    isSortable: false,
    cellRenderer: (order: Order) => {
      return `
        <div class="action-buttons">
          <button class="ghost" @click="(${handlers.onView.name})(order)">View</button>
          <button class="destructive" @click="(${handlers.onCancel.name})(order)">Cancel</button>
        </div>
      `;
