import type { Column } from "elements";
import { Button } from "elements";
import { h } from "vue";
import type { Order, OrderStatus } from "./types";

export const ORDER_STATUS_MAP: Record<OrderStatus, { label: string; statusClasses: string }> = {
  pending: { label: "Pending", statusClasses: "status-pending" },
  processing: { label: "Processing", statusClasses: "status-processing" },
  shipped: { label: "Shipped", statusClasses: "status-shipped" },
  delivered: { label: "Delivered", statusClasses: "status-delivered" },
  cancelled: { label: "Cancelled", statusClasses: "status-cancelled" },
};

const currencyFormatter = new Intl.NumberFormat("en-US", {
  style: "currency",
  currency: "USD",
});

const dateFormatter = new Intl.DateTimeFormat("en-US", {
  dateStyle: "medium",
});

export interface OrderColumnHandlers {
  onView: (order: Order) => void;
  onCancel: (order: Order) => void;
}

export const createColumns = (handlers: OrderColumnHandlers): Column<Order>[] => [
  {
    id: "id",
    label: "Order",
    cell: ({ row }) => h("span", { style: "font-family: monospace" }, `#ORD-${row.original.id}`),
  },
  {
    id: "customer",
    label: "Customer",
    isSortable: true,
  },
  {
    id: "status",
    label: "Status",
    cell: ({ row }) => {
      const statusInfo = ORDER_STATUS_MAP[row.original.status];
      return h("span", { class: statusInfo.statusClasses }, statusInfo.label);
    },
  },
  {
    id: "items",
    label: "Items",
    isSortable: true,
  },
  {
    id: "total",
    label: "Total",
    cell: ({ row }) => h("span", null, currencyFormatter.format(row.original.total)),
    isSortable: true,
  },
  {
    id: "date",
    label: "Date",
    cell: ({ row }) => h("span", null, dateFormatter.format(new Date(row.original.date))),
    isSortable: true,
  },
  {
    id: "actions",
    label: "Actions",
    cell: ({ row }) => [
      h(
        Button,
        {
          variant: "ghost",
          size: "sm",
          onClick: () => handlers.onView(row.original),
        },
        () => "View",
      ),
      h(
        Button,
        {
          variant: "destructive",
          size: "sm",
          onClick: () => handlers.onCancel(row.original),
        },
        () => "Cancel",
      ),
    ],
  },
];

export type OrderStatus = "pending" | "processing" | "shipped" | "delivered" | "cancelled";

export interface Order {
  id: string;
  customer: string;
  status: OrderStatus;
  items: number;
  total: number;
  date: string;
}

export interface OrderColumnHandlers {
  onView: (order: Order) => void;
  onCancel: (order: Order) => void;
}

